@Component
public class ConnectionPool {

    private HikariDataSource dataSource;

    @PostConstruct
    public void init() {
        // Called after all dependencies are injected
        // Good place for validation and resource initialization
        dataSource = buildDataSource();
    }

    @PreDestroy
    public void shutdown() {
        // Called during context close — before JVM exit
        if (dataSource != null && !dataSource.isClosed()) {
            dataSource.close();
        }
    }

    private HikariDataSource buildDataSource() {
        HikariConfig config = new HikariConfig();
        config.setJdbcUrl("jdbc:postgresql://localhost:5432/mydb");
        config.setMaximumPoolSize(20);
        return new HikariDataSource(config);
    }
}

@Configuration
public class TomcatConfig {

    // WebServerFactoryCustomizer applies before the server starts
    @Bean
    public WebServerFactoryCustomizer<TomcatServletWebServerFactory> tomcatCustomizer() {
        return factory -> {
            factory.addConnectorCustomizers(connector -> {
                connector.setMaxPostSize(10 * 1024 * 1024); // 10MB
                connector.setURIEncoding("UTF-8");
            });
            factory.addContextCustomizers(context -> {
                context.setReloadable(false);
            });
        };
    }

    // Full control: replace factory entirely
    @Bean
    public TomcatServletWebServerFactory servletWebServerFactory() {
        TomcatServletWebServerFactory factory = new TomcatServletWebServerFactory();
        factory.setPort(8080);
        factory.setSessionTimeout(Duration.ofMinutes(30));
        factory.addErrorPages(new ErrorPage(HttpStatus.NOT_FOUND, "/404"));
        return factory;
    }
}

