// Runs before the ApplicationContext is created
// Register in META-INF/spring.factories:
// org.springframework.boot.env.EnvironmentPostProcessor=
//   com.example.VaultEnvironmentPostProcessor

public class VaultEnvironmentPostProcessor implements EnvironmentPostProcessor {

    @Override
    public void postProcessEnvironment(ConfigurableEnvironment env,
                                       SpringApplication application) {
        // Fetch secrets from Vault (or any external source)
        Map<String, Object> secrets = fetchFromVault();

        // Create a new PropertySource with higher priority than application.yml
        MapPropertySource vaultSource =
            new MapPropertySource("vault", secrets);

        // addFirst = highest priority (after command-line args)
        env.getPropertySources().addFirst(vaultSource);
    }

    private Map<String, Object> fetchFromVault() {
        // Real implementation calls Vault HTTP API or SDK
        Map<String, Object> secrets = new HashMap<>();
        secrets.put("spring.datasource.password", "fetched-from-vault");
        return secrets;
    }
}

@Component
@Order(Ordered.HIGHEST_PRECEDENCE)
public class MdcFilter extends OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain chain)
            throws ServletException, IOException {

        String requestId = Optional
            .ofNullable(request.getHeader("X-Request-ID"))
            .orElse(UUID.randomUUID().toString());

        try {
            MDC.put("requestId", requestId);
            MDC.put("method", request.getMethod());
            MDC.put("uri", request.getRequestURI());
            // traceId injected by Micrometer Tracing if configured
            chain.doFilter(request, response);
        } finally {
            MDC.clear(); // always clear — thread may be reused
        }
    }
}

// Propagate MDC to async tasks running in a thread pool
@Bean
public TaskExecutor asyncExecutor() {
    ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
    executor.setCorePoolSize(10);
    executor.setMaxPoolSize(50);
    executor.setQueueCapacity(500);
    // MDCTaskDecorator copies MDC context from submitting thread to worker thread
    executor.setTaskDecorator(new MDCTaskDecorator());
    executor.initialize();
    return executor;
}

// MDCTaskDecorator implementation
public class MDCTaskDecorator implements TaskDecorator {
    @Override
    public Runnable decorate(Runnable runnable) {
        Map<String, String> contextMap = MDC.getCopyOfContextMap();
        return () -> {
            try {
                if (contextMap != null) {
                    MDC.setContextMap(contextMap);
                }
                runnable.run();
            } finally {
                MDC.clear();
            }
        };
    }
}

